class Solution {
    public int maxScore(int[] nums) {
        Arrays.sort(nums);
        int res = 0;
        for (int i = nums.length - 1; i >= nums.length / 2; i--) {
            res += i * gcd(nums[i], nums[nums.length - i - 1]);
        }
        return res;
    }

    private int gcd(int x, int y) {
        if (y == 0) return x;
        return gcd(y, x % y);
    }
}
